      "id": "actor",
      "fact": "顧客是造成商品消失的人",
      "role": "actor"
    },
    {
      "id": "action",
      "fact": "顧客用背包壓住自動門感應區並趁機拿走商品",
      "role": "action"
    },
    {
      "id": "cause",
      "fact": "自動門與監視器死角掩護了他的行動",
      "role": "cause"
    }
  ],
  "supporting_facts": [
    {
      "id": "misdirection",
      "fact": "旁人把監視畫面誤解成全程沒人靠近或幽靈作祟"
    },
    {
      "id": "hide",
      "fact": "商品被藏進外套內層帶離現場"
    }
  ]
}
謎面：
{
  "surface_story": "便利商店的自動門反覆開合，限定商品卻不翼而飛，全程無人靠近。監視器拍下空門晃動的畫面後，店內眾人皆以為是幽靈作祟。"
}
誤導與錯誤假設：
{
  "misleading_assumptions": [
    "幽靈作祟",
    "店員內部作案"
  ],
  "forbidden_assumptions": [
    "商品自己移動",
    "沒有任何顧客接近貨架"
  ]
}

